const createLabel = async (
  db: Database,
  opts: { uri: string; cid: string; val: string; src?: string },
) => {
  await db.db
    .insertInto('label')
    .values({
      uri: opts.uri,
      cid: opts.cid,
      val: opts.val,
      cts: new Date().toISOString(),
      neg: false,
      src: opts.src ?? EXAMPLE_LABELER,
    })
    .execute()
}

const setVerifier = async (db: Database, did: string) => {
  await db.db
    .updateTable('actor')
    .set({ trustedVerifier: true })
    .where('did', '=', did)
    .execute()
}
